    if pd.isna(x):
        return ""
    try:
        x = float(str(x).replace(",", ""))
        if x < 0:
            return f"({abs(x):,.0f})".replace(",", ".")
        else:
            return f"{x:,.0f}".replace(",", ".")
    except:
