                            df_reset.columns = ['NumeroConto'] + list(df_reset.columns[1:])
                            perturb_data = df_reset.to_dict('records')
                    except Exception:
                        pass
                runs.append({
                    'id': fname,
                    'filename': fname,
                    'timestamp': ts,
                    'label': label,
                    'request': request_text,
                    'markdown': markdown_truncated,
                    'perturbData': perturb_data,
                    'status': 'completed'
                })
            except Exception:
                pass
except Exception:
